/**
 * Claude × Notion 아카이브 시스템 — Google Drive 업로더
 * 
 * 사용법:
 * 1. script.google.com 접속
 * 2. 새 프로젝트 생성
 * 3. 아래 코드 전체 붙여넣기
 * 4. 상단 실행 버튼(▶) 클릭 → uploadHTMLToDrive 함수 선택 → 실행
 * 5. 권한 허용 후 → 내 드라이브에서 파일 확인
 */

function uploadHTMLToDrive() {

  // ── 1. HTML 파일 내용 (Base64 인코딩) ──────────────────────────────────────
  const base64Content = "PCFET0NUWVBFIGh0bWw+CjxodG1sIGxhbmc9ImtvIj4KPGhlYWQ+CjxtZXRhIGNoYXJzZXQ9IlVURi04Ij4KPG1ldGEgbmFtZT0idmlld3BvcnQiIGNvbnRlbnQ9IndpZHRoPWRldmljZS13aWR0aCwgaW5pdGlhbC1zY2FsZT0xLjAiPgo8dGl0bGU+Q2xhdWRlIMOXIE5vdGlvbiDsnpDrj5kg7JWE7Lm07J2067iMIOyLnOyKpO2FnDwvdGl0bGU+";

  // ── 2. 저장 설정 ────────────────────────────────────────────────────────────
  const fileName    = "claude_notion_archive_system.html";
  const folderName  = "Claude Artifacts";   // 저장할 폴더명 (없으면 자동 생성)
  const mimeType    = "text/html";

  // ── 3. 폴더 찾기 또는 생성 ──────────────────────────────────────────────────
  let folder;
  const folders = DriveApp.getFoldersByName(folderName);
  if (folders.hasNext()) {
    folder = folders.next();
    Logger.log("기존 폴더 사용: " + folder.getName());
  } else {
    folder = DriveApp.createFolder(folderName);
    Logger.log("새 폴더 생성: " + folder.getName());
  }

  // ── 4. HTML 원본 내용 (직접 삽입) ───────────────────────────────────────────
  const htmlContent = getHTMLContent();

  // ── 5. 파일 생성 ────────────────────────────────────────────────────────────
  const blob = Utilities.newBlob(htmlContent, mimeType, fileName);

  // 동일한 이름의 파일이 있으면 업데이트, 없으면 새로 생성
  const existingFiles = folder.getFilesByName(fileName);
  let file;

  if (existingFiles.hasNext()) {
    file = existingFiles.next();
    file.setContent(htmlContent);
    Logger.log("기존 파일 업데이트 완료");
  } else {
    file = folder.createFile(blob);
    Logger.log("새 파일 생성 완료");
  }

  // ── 6. 링크 공유 설정 (선택) ────────────────────────────────────────────────
  // 아래 줄의 주석을 해제하면 링크가 있는 모든 사람이 볼 수 있게 됩니다
  // file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

  // ── 7. 완료 알림 ────────────────────────────────────────────────────────────
  const fileUrl = file.getUrl();
  Logger.log("✅ 업로드 완료!");
  Logger.log("📁 폴더: " + folder.getName());
  Logger.log("📄 파일명: " + file.getName());
  Logger.log("🔗 링크: " + fileUrl);

  // 브라우저 알림 (Apps Script UI)
  const ui = SpreadsheetApp.getUi ? SpreadsheetApp.getUi() : null;

  // 알림 팝업 표시
  Browser.msgBox(
    "✅ Google Drive 저장 완료",
    "파일명: " + fileName + "\n폴더: " + folderName + "\n\n링크:\n" + fileUrl,
    Browser.Buttons.OK
  );
}


/**
 * HTML 파일 내용 반환
