      --color-border-primary: rgba(255,255,255,0.28);
    }
  }
  body { font-family: var(--font-sans); background: var(--color-background-secondary); color: var(--color-text-primary); min-height: 100vh; padding: 24px 16px 48px; }
  .wrapper { max-width: 760px; margin: 0 auto; }
  .container { padding: 8px 0 24px; }
  .hero { display: flex; align-items: center; gap: 12px; padding: 18px 20px; background: var(--color-background-primary); border-radius: var(--border-radius-lg); border: 0.5px solid var(--color-border-tertiary); margin-bottom: 20px; }
  .hero-icon { width: 44px; height: 44px; border-radius: var(--border-radius-md); background: var(--color-background-info); display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
  .hero-icon svg { width: 22px; height: 22px; stroke: var(--color-text-info); fill: none; stroke-width: 1.8; }
